  1→/**
  2→ * Policy Node Acceptance Test Kit
  3→ *
  4→ * Extends the intent-test-kit with policy-specific helpers.
  5→ * All helpers use business language -- no technical jargon in function names.
  6→ *
  7→ * Driving ports:
  8→ *   Direct DB for policy schema, graph edges, and policy gate evaluation
  9→ *   POST /api/intents/:id/evaluate (SurrealQL EVENT target -- via intent-test-kit)
 10→ */
 11→import { RecordId, type Surreal } from "surrealdb";
 12→
 13→// Re-export everything from intent-test-kit (which re-exports orchestrator-test-kit)
 14→export {
 15→  setupOrchestratorSuite,
 16→  createTestUser,
 17→  createTestWorkspace,
 18→  createReadyTask,
 19→  createTestProject,
 20→  getTestUserBearerToken,
 21→  fetchJson,
 22→  fetchRaw,
 23→  createDraftIntent,
 24→  submitIntent,
 25→  getIntentStatus,
 26→  getIntentRecord,
 27→  getIntentEvaluation,
 28→  waitForIntentStatus,
 29→  simulateEvaluation,
 30→  createTestIdentity,
 31→  listPendingIntents,
 32→  wireIntentEvaluationEvent,
 33→  type OrchestratorTestRuntime,
 34→  type TestUser,
 35→  type TestUserWithToken,
 36→  type TestWorkspace,
 37→  type TestTask,
 38→  type TestProject,
 39→  type IntentStatus,
 40→  type IntentRecord,
 41→  type EvaluationResult,
 42→  type ActionSpec,
 43→  type BudgetLimit,
 44→  type CreateIntentOptions,
 45→} from "../intent-node/intent-test-kit";
 46→
 47→// ---------------------------------------------------------------------------
 48→// Policy-Specific Types
 49→// ---------------------------------------------------------------------------
 50→
 51→export type RulePredicate = {
 52→  field: string;
 53→  operator: "eq" | "neq" | "lt" | "lte" | "gt" | "gte" | "in" | "not_in" | "exists";
 54→  value: string | number | boolean | string[];
 55→};
 56→
 57→export type RuleCondition = RulePredicate | RulePredicate[];
 58→
 59→export type PolicyRule = {
 60→  id: string;
 61→  condition: RuleCondition;
 62→  effect: "allow" | "deny";
 63→  priority: number;
 64→};
 65→
 66→export type PolicySelector = {
 67→  workspace?: string;
 68→  agent_role?: string;
 69→  resource?: string;
 70→};
 71→
 72→export type PolicyStatus = "draft" | "testing" | "active" | "deprecated" | "superseded";
 73→
 74→export type PolicyRecord = {
 75→  id: RecordId<"policy">;
 76→  title: string;
 77→  description?: string;
 78→  version: number;
 79→  status: PolicyStatus;
 80→  selector: PolicySelector;
 81→  rules: PolicyRule[];
 82→  human_veto_required: boolean;
 83→  max_ttl?: string;
 84→  created_by: RecordId<"identity">;
 85→  workspace: RecordId<"workspace">;
 86→  supersedes?: RecordId<"policy">;
 87→  created_at: string;
 88→  updated_at?: string;
 89→};
 90→
 91→export type PolicyTraceEntry = {
 92→  policy_id: string;
 93→  policy_version: number;
 94→  rule_id: string;
 95→  effect: "allow" | "deny";
 96→  matched: boolean;
 97→  priority: number;
 98→};
 99→
100→export type CreatePolicyOptions = {
101→  title: string;
102→  description?: string;
103→  status?: PolicyStatus;
104→  selector?: PolicySelector;
105→  rules: PolicyRule[];
106→  human_veto_required?: boolean;
107→  max_ttl?: string;
108→};
109→
110→// ---------------------------------------------------------------------------
111→// Domain Helpers -- Business Language Layer
112→// ---------------------------------------------------------------------------
113→
114→/**
115→ * Creates a policy record directly in the database.
116→ * Used as a Given-step precondition for scenarios.
117→ */
118→export async function createPolicy(
119→  surreal: Surreal,
120→  workspaceId: string,
121→  createdById: string,
122→  opts: CreatePolicyOptions,
123→): Promise<{ policyId: string; policyRecord: RecordId<"policy"> }> {
124→  const policyId = `policy-${crypto.randomUUID()}`;
125→  const policyRecord = new RecordId("policy", policyId);
126→  const workspaceRecord = new RecordId("workspace", workspaceId);
127→  const createdByRecord = new RecordId("identity", createdById);
128→
129→  const content: Record<string, unknown> = {
130→    title: opts.title,
131→    version: 1,
132→    status: opts.status ?? "draft",
133→    selector: opts.selector ?? {},
134→    rules: opts.rules,
135→    human_veto_required: opts.human_veto_required ?? false,
136→    created_by: createdByRecord,
137→    workspace: workspaceRecord,
138→    created_at: new Date(),
139→  };
140→
141→  if (opts.description) content.description = opts.description;
142→  if (opts.max_ttl) content.max_ttl = opts.max_ttl;
143→
144→  await surreal.query(`CREATE $policy CONTENT $content;`, {
145→    policy: policyRecord,
146→    content,
147→  });
148→
149→  return { policyId, policyRecord };
150→}
151→
152→/**
153→ * Activates a draft policy and creates graph edges.
154→ * Atomic: status change + governing + protects edges in one transaction.
155→ */
156→export async function activatePolicy(
157→  surreal: Surreal,
158→  policyId: string,
159→  creatorId: string,
160→  workspaceId: string,
161→): Promise<void> {
162→  const policyRecord = new RecordId("policy", policyId);
163→  const creatorRecord = new RecordId("identity", creatorId);
164→  const workspaceRecord = new RecordId("workspace", workspaceId);
165→
166→  await surreal.query(`
167→    BEGIN TRANSACTION;
168→      UPDATE $policy SET status = 'active', updated_at = time::now();
169→      RELATE $creator->governing->$policy SET created_at = time::now();
170→      RELATE $policy->protects->$workspace SET created_at = time::now();
171→    COMMIT TRANSACTION;
172→  `, {
173→    policy: policyRecord,
174→    creator: creatorRecord,
175→    workspace: workspaceRecord,
176→  });
177→}
178→
179→/**
180→ * Deprecates a policy and removes all graph edges.
181→ */
182→export async function deprecatePolicy(
183→  surreal: Surreal,
184→  policyId: string,
185→): Promise<void> {
186→  const policyRecord = new RecordId("policy", policyId);
187→
188→  await surreal.query(`
189→    BEGIN TRANSACTION;
190→      UPDATE $policy SET status = 'deprecated', updated_at = time::now();
191→      DELETE governing WHERE out = $policy;
192→      DELETE protects WHERE in = $policy;
193→    COMMIT TRANSACTION;
194→  `, { policy: policyRecord });
195→}
196→
197→/**
198→ * Queries the full policy record from the database.
199→ */
200→export async function getPolicyRecord(
201→  surreal: Surreal,
202→  policyId: string,
203→): Promise<PolicyRecord> {
204→  const policyRecord = new RecordId("policy", policyId);
205→  const rows = (await surreal.query(`SELECT * FROM $policy;`, {
206→    policy: policyRecord,
207→  })) as Array<Array<PolicyRecord>>;
208→  const result = rows[0]?.[0];
209→  if (!result) throw new Error(`Policy ${policyId} not found`);
210→  return result;
211→}
212→
213→/**
214→ * Loads active policies for an identity+workspace via graph traversal.
215→ * Mirrors the production loadActivePolicies query pattern.
216→ */
217→export async function loadActivePoliciesForIdentity(
218→  surreal: Surreal,
219→  identityId: string,
220→  workspaceId: string,
221→): Promise<PolicyRecord[]> {
222→  const identityRecord = new RecordId("identity", identityId);
223→  const workspaceRecord = new RecordId("workspace", workspaceId);
224→
225→  // Identity-linked policies
226→  const identityPolicies = (await surreal.query(
227→    `SELECT ->governing->policy.* AS policies FROM $identity;`,
228→    { identity: identityRecord },
229→  )) as Array<Array<{ policies: PolicyRecord[] }>>;
230→
231→  // Workspace-linked policies
232→  const workspacePolicies = (await surreal.query(
233→    `SELECT <-protects<-policy.* AS policies FROM $workspace;`,
234→    { workspace: workspaceRecord },
235→  )) as Array<Array<{ policies: PolicyRecord[] }>>;
236→
237→  const idPolicies = identityPolicies[0]?.[0]?.policies ?? [];
238→  const wsPolicies = workspacePolicies[0]?.[0]?.policies ?? [];
239→
240→  // Deduplicate by policy ID and filter active only
241→  const seen = new Set<string>();
242→  const all: PolicyRecord[] = [];
243→  for (const p of [...idPolicies, ...wsPolicies]) {
244→    const id = p.id.id as string;
245→    if (!seen.has(id) && p.status === "active") {
246→      seen.add(id);
247→      all.push(p);
248→    }
249→  }
250→  return all;
251→}
252→
253→/**
254→ * Simulates the policy gate evaluation result on an intent.
255→ * Used to set up post-policy-gate state for downstream tests.
256→ */
257→export async function simulatePolicyGateResult(
258→  surreal: Surreal,
259→  intentId: string,
260→  result: {
261→    decision: "APPROVE" | "REJECT";
262→    risk_score: number;
263→    reason: string;
264→    policy_only: boolean;
265→    policy_trace: PolicyTraceEntry[];
266→    human_veto_required?: boolean;
267→  },
268→  resultStatus: "authorized" | "pending_veto" | "vetoed",
269→): Promise<void> {
270→  const intentRecord = new RecordId("intent", intentId);
271→  const evalContent: Record<string, unknown> = {
272→    decision: result.decision,
273→    risk_score: result.risk_score,
274→    reason: result.reason,
275→    evaluated_at: new Date(),
276→    policy_only: result.policy_only,
277→    policy_trace: result.policy_trace,
278→  };
279→  if (result.human_veto_required !== undefined) {
