150→describe("Milestone 1: Policy Lifecycle Management (US-2)", () => {
151→  // ---------------------------------------------------------------------------
152→  // US-2: Draft -> Active transition with audit event
153→  // AC-2 happy path
154→  // ---------------------------------------------------------------------------
155→  it("activates a draft policy and creates graph edges atomically", async () => {
156→    const { baseUrl, surreal } = getRuntime();
157→
158→    // Given a draft policy
159→    const user = await createTestUser(baseUrl, "m1-activate");
160→    const workspace = await createTestWorkspace(baseUrl, user);
161→    const adminId = await createTestIdentity(surreal, "admin-1", "human", workspace.workspaceId);
162→
163→    const { policyId } = await createPolicy(surreal, workspace.workspaceId, adminId, {
164→      title: "API Rate Limit Policy",
165→      rules: [{
166→        id: "rate_limit",
167→        condition: { field: "action_spec.action", operator: "eq", value: "api_call" },
168→        effect: "allow",
169→        priority: 10,
170→      }],
171→    });
172→
173→    // When the admin activates the policy
174→    await activatePolicy(surreal, policyId, adminId, workspace.workspaceId);
175→
176→    // Then the policy status is active
177→    const record = await getPolicyRecord(surreal, policyId);
178→    expect(record.status).toBe("active");
179→    expect(record.updated_at).toBeDefined();
180→
181→    // And the governing edge exists (identity -> policy)
182→    const identityRecord = new RecordId("identity", adminId);
183→    const governingRows = (await surreal.query(
184→      `SELECT ->governing->policy AS policies FROM $identity;`,
185→      { identity: identityRecord },
186→    )) as Array<Array<{ policies: RecordId[] }>>;
187→    const governedPolicies = governingRows[0]?.[0]?.policies ?? [];
188→    const found = governedPolicies.some(p => (p.id as string) === policyId);
189→    expect(found).toBe(true);
190→
191→    // And the protects edge exists (policy -> workspace)
192→    const policyRecord = new RecordId("policy", policyId);
193→    const protectsRows = (await surreal.query(
194→      `SELECT ->protects->workspace AS workspaces FROM $policy;`,
195→      { policy: policyRecord },
196→    )) as Array<Array<{ workspaces: RecordId[] }>>;
197→    const protectedWorkspaces = protectsRows[0]?.[0]?.workspaces ?? [];
198→    expect(protectedWorkspaces.length).toBeGreaterThanOrEqual(1);
199→  }, 120_000);
200→
201→  // ---------------------------------------------------------------------------
202→  // US-2: Active -> Deprecated removes edges
203→  // AC-2 deprecation path
204→  // ---------------------------------------------------------------------------
205→  it("deprecating a policy removes all governing and protects edges", async () => {
206→    const { baseUrl, surreal } = getRuntime();
207→
208→    // Given an active policy with graph edges
209→    const user = await createTestUser(baseUrl, "m1-deprecate");
210→    const workspace = await createTestWorkspace(baseUrl, user);
211→    const adminId = await createTestIdentity(surreal, "admin-1", "human", workspace.workspaceId);
212→
213→    const { policyId } = await createPolicy(surreal, workspace.workspaceId, adminId, {
214→      title: "Legacy Auth Policy",
215→      rules: [{
216→        id: "legacy_check",
217→        condition: { field: "action_spec.action", operator: "eq", value: "auth" },
218→        effect: "allow",
219→        priority: 5,
220→      }],
221→    });
222→    await activatePolicy(surreal, policyId, adminId, workspace.workspaceId);
223→
224→    // When the admin deprecates the policy
225→    await deprecatePolicy(surreal, policyId);
226→
227→    // Then the policy status is deprecated
228→    const record = await getPolicyRecord(surreal, policyId);
