 4→// --- Intent Status (state machine states) ---
 5→
 6→export type IntentStatus =
 7→  | "draft"
 8→  | "pending_auth"
 9→  | "pending_veto"
10→  | "authorized"
11→  | "executing"
12→  | "completed"
13→  | "vetoed"
