247→      expires_at: intent.veto_expires_at
248→        ? (intent.veto_expires_at instanceof Date
249→          ? intent.veto_expires_at.toISOString()
250→          : String(intent.veto_expires_at))
251→        : "",
252→    }, 200);
253→  };
254→
255→  const handleApprove = async (
256→    workspaceId: string,
257→    intentId: string,
258→  ): Promise<Response> => {
259→    const result = await updateIntentStatus(surreal, intentId, "authorized");
260→
261→    if (!result.ok) {
262→      logError("intent.approve.failed", "Failed to approve intent", new Error(result.error), {
263→        intentId,
264→        workspaceId,
265→      });
266→      return jsonError(result.error, 409);
267→    }
268→
269→    logInfo("intent.approved", "Intent approved by human", {
270→      intentId,
271→      workspaceId,
272→    });
273→
274→    return jsonResponse({
275→      intentId,
276→      status: "authorized",
277→    }, 200);
278→  };
279→
280→  const handleConstrain = async (
281→    workspaceId: string,
282→    intentId: string,
283→    request: Request,
284→  ): Promise<Response> => {
285→    let body: { constrained_authorization_details: BrainAction[] };
286→    try {
287→      body = await request.json() as { constrained_authorization_details: BrainAction[] };
288→    } catch {
289→      return jsonError("Invalid JSON body", 400);
290→    }
291→
292→    if (!body.constrained_authorization_details || !Array.isArray(body.constrained_authorization_details)) {
293→      return jsonError("constrained_authorization_details is required", 400);
294→    }
295→
296→    const intent = await getIntentById(surreal, intentId);
297→    if (!intent) {
298→      return jsonError("Intent not found", 404);
299→    }
300→
301→    if (intent.status !== "pending_veto") {
302→      return jsonError(`Intent is in '${intent.status}' status, expected 'pending_veto'`, 409);
303→    }
304→
305→    const originalDetails = intent.authorization_details ?? [];
306→    const proposedDetails = body.constrained_authorization_details;
307→
308→    // Validate each proposed action against its original
309→    for (let i = 0; i < proposedDetails.length; i++) {
310→      const original = originalDetails[i];
311→      const proposed = proposedDetails[i];
312→
313→      if (!original) {
314→        return jsonError(`No original authorization_details at index ${i}`, 400);
315→      }
316→
317→      const boundsCheck = validateTighterBounds(original, proposed);
318→      if (!boundsCheck.valid) {
319→        return jsonError(
320→          `Constraint validation failed: ${boundsCheck.violations.join("; ")}`,
321→          400,
322→        );
323→      }
324→    }
325→
326→    // Update intent with tighter constraints and authorize
327→    const record = await updateIntentStatus(surreal, intentId, "authorized", {});
328→    if (!record.ok) {
329→      return jsonError(record.error, 409);
330→    }
331→
332→    // Update the authorization_details with the constrained version
333→    await surreal.query(
334→      "UPDATE $record SET authorization_details = $details;",
335→      {
336→        record: new RecordId("intent", intentId),
337→        details: proposedDetails,
338→      },
339→    );
340→
341→    logInfo("intent.constrained", "Intent constrained and authorized by human", {
342→      intentId,
343→      workspaceId,
344→    });
345→
346→    return jsonResponse({
347→      intentId,
348→      status: "authorized",
349→    }, 200);
350→  };
351→
352→  return { handleEvaluate, handleVeto, handleListPending, handleConsent, handleApprove, handleConstrain };
353→}
