126→describe("Walking Skeleton: Empty policy set preserves backward compatibility", () => {
127→  // ---------------------------------------------------------------------------
128→  // Skeleton 2: No policies -> intent passes through to LLM tier
129→  // US-9 backward compatibility
130→  // ---------------------------------------------------------------------------
131→  it("intent passes through policy gate when no active policies exist", async () => {
132→    const { baseUrl, surreal } = getRuntime();
133→
134→    // Given a workspace with NO active policies
135→    const user = await createTestUser(baseUrl, "skel-empty");
136→    const workspace = await createTestWorkspace(baseUrl, user);
137→    const agentId = await createTestIdentity(surreal, "coding-agent", "agent", workspace.workspaceId);
138→
139→    // When an agent submits an intent
140→    const { intentId } = await createDraftIntent(
141→      surreal,
142→      workspace.workspaceId,
143→      agentId,
144→      {
145→        goal: "Add input validation to login form",
146→        reasoning: "Improve security by validating email format",
147→        action_spec: { provider: "file_editor", action: "edit_file", params: { target: "src/Login.tsx" } },
148→      },
149→    );
150→
151→    await submitIntent(surreal, intentId);
152→
153→    // Then the policy gate finds no active policies
154→    const policies = await loadActivePoliciesForIdentity(surreal, agentId, workspace.workspaceId);
155→    expect(policies).toHaveLength(0);
156→
157→    // And the intent passes through to LLM evaluation (simulated as approved)
158→    await simulatePolicyGateResult(surreal, intentId, {
159→      decision: "APPROVE",
160→      risk_score: 10,
161→      reason: "Safe file edit within scope. Low risk.",
162→      policy_only: false,
