164→    }, "authorized");
165→
166→    // Then the intent is authorized
167→    const status = await getIntentStatus(surreal, intentId);
168→    expect(status).toBe("authorized");
169→
170→    // And the evaluation is NOT policy-only (LLM tier ran)
