      expect(result).toEqual({ route: "auto_approve" });
    });

    test("returns auto_approve when APPROVE and risk_score equals custom threshold", () => {
      const result = routeByRisk(approveResult(50), { threshold: 50 });
      expect(result).toEqual({ route: "auto_approve" });
    });
  });

